import React, { useState } from 'react';
import { View, WebView } from 'react-native';

const App = () => {
  const [msg, setMsg] = useState(null);

  return (
    <View style={{ flex: 1 }}>
      <WebView
        source={{ uri: 'https://example.com' }}
        scalesPageToFit={true}
        javaScriptEnabled={true}
        onMessage={(event) => setMsg(event.nativeEvent.data)}
      />
      {msg && (
        <View>
          <Text>Received message from webview:</Text>
          <Text>{msg}</Text>
        </View>
      )}
    </View>
  );
};

const Bridge = ({ children }) => {
  const [nativeModules] = useState(new NativeModules());

  return (
    <WebView
      source={{ uri: 'https://example.com' }}
      scalesPageToFit={true}
      javaScriptEnabled={true}
      injectedJavaScript={`window.ReactNativeWebView.postMessage = function(message) { global.postMessage(message); };`}
      onMessage={(event) => {
        if (event.nativeEvent.data === 'takePicture') {
          nativeModules.takePicture();
        } else if (event.nativeEvent.data === 'getLocation') {
          nativeModules.getLocation();
        }
      }}
    >
      {children}
    </WebView>
  );
};